export const ConfigChangeEvent: MessageFns<ConfigChangeEvent> = {
  encode(message: ConfigChangeEvent, writer: BinaryWriter = new BinaryWriter()): BinaryWriter {
    if (message.key !== "") {
      writer.uint32(10).string(message.key);
    }
    if (message.oldValue !== "") {
      writer.uint32(18).string(message.oldValue);
    }
    if (message.newValue !== "") {
      writer.uint32(26).string(message.newValue);
    }
    if (message.namespace !== "") {
      writer.uint32(34).string(message.namespace);
    }
    if (message.version !== 0) {
      writer.uint32(40).int32(message.version);
    }
    if (message.changedAt !== undefined) {
      Timestamp.encode(toTimestamp(message.changedAt), writer.uint32(50).fork()).join();
    }
    return writer;
  },

  decode(input: BinaryReader | Uint8Array, length?: number): ConfigChangeEvent {
    const reader = input instanceof BinaryReader ? input : new BinaryReader(input);
    const end = length === undefined ? reader.len : reader.pos + length;
    const message = createBaseConfigChangeEvent();
    while (reader.pos < end) {
      const tag = reader.uint32();
      switch (tag >>> 3) {
        case 1: {
          if (tag !== 10) {
            break;
          }

          message.key = reader.string();
          continue;
        }
        case 2: {
          if (tag !== 18) {
            break;
          }

          message.oldValue = reader.string();
          continue;
        }
        case 3: {
          if (tag !== 26) {
            break;
          }

          message.newValue = reader.string();
          continue;
        }
        case 4: {
          if (tag !== 34) {
            break;
          }

          message.namespace = reader.string();
          continue;
        }
        case 5: {
          if (tag !== 40) {
            break;
          }

          message.version = reader.int32();
          continue;
        }
        case 6: {
          if (tag !== 50) {
            break;
          }

          message.changedAt = fromTimestamp(Timestamp.decode(reader, reader.uint32()));
          continue;
        }
      }
      if ((tag & 7) === 4 || tag === 0) {
        break;
      }
      reader.skip(tag & 7);
    }
    return message;
  },

  fromJSON(object: any): ConfigChangeEvent {
    return {
      key: isSet(object.key) ? globalThis.String(object.key) : "",
      oldValue: isSet(object.oldValue)
        ? globalThis.String(object.oldValue)
        : isSet(object.old_value)
        ? globalThis.String(object.old_value)
        : "",
      newValue: isSet(object.newValue)
        ? globalThis.String(object.newValue)
        : isSet(object.new_value)
        ? globalThis.String(object.new_value)
        : "",
      namespace: isSet(object.namespace) ? globalThis.String(object.namespace) : "",
      version: isSet(object.version) ? globalThis.Number(object.version) : 0,
      changedAt: isSet(object.changedAt)
        ? fromJsonTimestamp(object.changedAt)
        : isSet(object.changed_at)
        ? fromJsonTimestamp(object.changed_at)
        : undefined,
    };
  },

  toJSON(message: ConfigChangeEvent): unknown {
    const obj: any = {};
    if (message.key !== "") {
      obj.key = message.key;
    }
    if (message.oldValue !== "") {
      obj.oldValue = message.oldValue;
    }
    if (message.newValue !== "") {
      obj.newValue = message.newValue;
    }
    if (message.namespace !== "") {
      obj.namespace = message.namespace;
    }
    if (message.version !== 0) {
      obj.version = Math.round(message.version);
    }
    if (message.changedAt !== undefined) {
      obj.changedAt = message.changedAt.toISOString();
    }
    return obj;
  },

  create<I extends Exact<DeepPartial<ConfigChangeEvent>, I>>(base?: I): ConfigChangeEvent {
    return ConfigChangeEvent.fromPartial(base ?? ({} as any));
  },
  fromPartial<I extends Exact<DeepPartial<ConfigChangeEvent>, I>>(object: I): ConfigChangeEvent {
    const message = createBaseConfigChangeEvent();
    message.key = object.key ?? "";
    message.oldValue = object.oldValue ?? "";
    message.newValue = object.newValue ?? "";
    message.namespace = object.namespace ?? "";
    message.version = object.version ?? 0;
    message.changedAt = object.changedAt ?? undefined;
    return message;
  },
};

